import { ComparisonChart } from './components/charts/ComparisonChart';
import { CumulativeInterestChart } from './components/charts/CumulativeInterestChart';
import { PaymentBreakupChart } from './components/charts/PaymentBreakupChart';
import { YearlySummaryChart } from './components/charts/YearlySummaryChart';

const App = () => {
  const {
    loan,
    setLoan,
    prePayments,
    addPrePayment,
    updatePrePayment,
    removePrePayment,
    rateChanges,
    addRateChange,
    updateRateChange,
    removeRateChange,
  } = useLoanData();
  const { summary, error } = useAmortization(loan, prePayments, rateChanges);
  const { reportRef, isGenerating, exportPdf } = useExportPdf();
  const {
    data: recommendations,
    loading: recLoading,
    error: recError,
    fetchRecommendations,
  } = useRecommendations(loan, prePayments, rateChanges);

  const [plannedPPs, setPlannedPPs] = useState<PrePayment[]>([]);
  const [activeTab, setActiveTab] = useState<'prepayments' | 'rates'>('prepayments');

  const simulatedResult = useMemo<AmortizationResult | null>(() => {
    if (!loan || plannedPPs.length === 0) return null;
    const allPPs = [...prePayments, ...plannedPPs];
    return calculateAmortization(loan, allPPs, rateChanges);
  }, [loan, prePayments, rateChanges, plannedPPs]);

  const activeResult = simulatedResult ?? summary?.withPrePayments ?? null;

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 via-white to-blue-50/30">
      {/* Header */}
      <header className="sticky top-0 z-30 border-b border-slate-200/80 bg-white/80 backdrop-blur-lg">
        <div className="mx-auto max-w-7xl px-4 sm:px-6 lg:px-8">
          <div className="flex h-16 items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="flex h-9 w-9 items-center justify-center rounded-xl bg-gradient-to-br from-blue-600 to-indigo-600 shadow-md shadow-blue-600/20">
                <svg
                  className="h-5 w-5 text-white"
                  fill="none"
                  viewBox="0 0 24 24"
                  strokeWidth="2"
                  stroke="currentColor"
                >
                  <path
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    d="M2.25 18.75a60.07 60.07 0 0115.797 2.101c.727.198 1.453-.342 1.453-1.096V18.75M3.75 4.5v.75A.75.75 0 013 6h-.75m0 0v-.375c0-.621.504-1.125 1.125-1.125H20.25M2.25 6v9m18-10.5v.75c0 .414.336.75.75.75h.75m-1.5-1.5h.375c.621 0 1.125.504 1.125 1.125v9.75c0 .621-.504 1.125-1.125 1.125h-.375m1.5-1.5H21a.75.75 0 00-.75.75v.75m0 0H3.75m0 0h-.375a1.125 1.125 0 01-1.125-1.125V15m1.5 1.5v-.75A.75.75 0 003 15h-.75M15 10.5a3 3 0 11-6 0 3 3 0 016 0zm3 0h.008v.008H18V10.5zm-12 0h.008v.008H6V10.5z"
                  />
                </svg>
              </div>
              <div>
                <h1 className="text-lg font-bold text-slate-900 leading-tight">Loan Analyser</h1>
                <p className="text-xs text-slate-500 hidden sm:block">
                  Smart insights for your loan
                </p>
              </div>
            </div>
            <div className="flex items-center gap-3" style={{ display: 'none' }}>
              {summary && loan && (
                <button
                  onClick={() => exportPdf()}
                  disabled={isGenerating}
                  className="cursor-pointer group inline-flex items-center gap-2 rounded-xl bg-slate-900 px-4 py-2 text-sm font-medium text-white shadow-sm transition-all hover:bg-slate-800 hover:shadow-md disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  {isGenerating ? (
                    <>
                      <svg className="h-4 w-4 animate-spin" viewBox="0 0 24 24" fill="none">
                        <circle
                          className="opacity-25"
                          cx="12"
                          cy="12"
                          r="10"
                          stroke="currentColor"
                          strokeWidth="4"
                        />
                        <path
                          className="opacity-75"
                          fill="currentColor"
                          d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"
                        />
                      </svg>
                      Generating...
                    </>
                  ) : (
                    <>
                      <svg
                        className="h-4 w-4 transition-transform group-hover:-translate-y-0.5"
                        fill="none"
                        stroke="currentColor"
                        strokeWidth="2"
                        viewBox="0 0 24 24"
                      >
                        <path
                          strokeLinecap="round"
                          strokeLinejoin="round"
                          d="M3 16.5v2.25A2.25 2.25 0 005.25 21h13.5A2.25 2.25 0 0021 18.75V16.5M16.5 12L12 16.5m0 0L7.5 12m4.5 4.5V3"
                        />
                      </svg>
                      Export PDF
                    </>
                  )}
                </button>
              )}
            </div>
          </div>
        </div>
      </header>

      <main className="mx-auto max-w-7xl px-3 sm:px-6 lg:px-8 py-5 sm:py-8 space-y-5 sm:space-y-8">
        {/* Loan Form */}
        <LoanForm loan={loan} onSubmit={setLoan} />

        {error && (
          <div className="flex items-center gap-3 rounded-xl border border-red-200 bg-red-50 px-4 py-3 text-sm text-red-700">
            <svg
              className="h-5 w-5 shrink-0 text-red-400"
              fill="none"
              viewBox="0 0 24 24"
              strokeWidth="1.5"
              stroke="currentColor"
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                d="M12 9v3.75m9-.75a9 9 0 11-18 0 9 9 0 0118 0zm-9 3.75h.008v.008H12v-.008z"
              />
            </svg>
            {error}
          </div>
        )}

        {/* Pre-Payments & Rate Changes — Tabbed */}
        {loan && (
          <div className="rounded-2xl border border-slate-200 bg-white shadow-sm overflow-hidden">
            <div className="flex border-b border-slate-200">
              <button
                onClick={() => setActiveTab('prepayments')}
                className={`cursor-pointer flex-1 px-4 sm:px-6 py-3 sm:py-3.5 text-sm font-medium transition-colors relative ${
                  activeTab === 'prepayments'
                    ? 'text-blue-600 bg-blue-50/50'
                    : 'text-slate-500 hover:text-slate-700 hover:bg-slate-50'
                }`}
              >
                Pre-Payments
                {prePayments.length > 0 && (
                  <span className="ml-2 inline-flex h-5 min-w-5 items-center justify-center rounded-full bg-blue-100 px-1.5 text-xs font-semibold text-blue-700">
                    {prePayments.length}
                  </span>
                )}
                {activeTab === 'prepayments' && (
                  <span className="absolute bottom-0 left-0 right-0 h-0.5 bg-blue-600" />
                )}
              </button>
              <button
                onClick={() => setActiveTab('rates')}
                className={`cursor-pointer flex-1 px-4 sm:px-6 py-3 sm:py-3.5 text-sm font-medium transition-colors relative ${
                  activeTab === 'rates'
                    ? 'text-indigo-600 bg-indigo-50/50'
                    : 'text-slate-500 hover:text-slate-700 hover:bg-slate-50'
                }`}
              >
                Rate Changes
                {rateChanges.length > 0 && (
                  <span className="ml-2 inline-flex h-5 min-w-5 items-center justify-center rounded-full bg-indigo-100 px-1.5 text-xs font-semibold text-indigo-700">
                    {rateChanges.length}
                  </span>
                )}
                {activeTab === 'rates' && (
                  <span className="absolute bottom-0 left-0 right-0 h-0.5 bg-indigo-600" />
                )}
              </button>
            </div>
            <div className="p-4 sm:p-6">
              {activeTab === 'prepayments' ? (
                <PrePaymentList
                  prePayments={prePayments}
                  onAdd={addPrePayment}
                  onUpdate={updatePrePayment}
                  onRemove={removePrePayment}
                />
              ) : (
                <RateChangeList
                  rateChanges={rateChanges}
                  onAdd={addRateChange}
                  onUpdate={updateRateChange}
                  onRemove={removeRateChange}
                />
              )}
            </div>
          </div>
        )}

        {summary && loan && (
          <>
            {/* Summary Cards */}
            <SummaryCards summary={summary} loan={loan} />

            {/* Recommendations */}
            <RecommendationPanel
              data={recommendations}
              loading={recLoading}
              error={recError}
              onFetch={fetchRecommendations}
            />

            {/* What-If Simulator */}
            <WhatIfSimulator
              plannedPPs={plannedPPs}
              onAdd={(pp) => setPlannedPPs((prev) => [...prev, pp])}
              onRemove={(id) => setPlannedPPs((prev) => prev.filter((p) => p.id !== id))}
              currentResult={summary.withPrePayments}
              simulatedResult={simulatedResult}
            />

            {/* Simulation Banner */}
            {simulatedResult && (
              <div className="flex flex-col sm:flex-row items-start sm:items-center gap-3 rounded-xl border border-amber-200 bg-gradient-to-r from-amber-50 to-orange-50 px-4 sm:px-5 py-3 text-sm">
                <div className="flex items-center gap-3 flex-1 min-w-0">
                  <div className="flex h-8 w-8 shrink-0 items-center justify-center rounded-lg bg-amber-100">
                    <svg
                      className="h-4 w-4 text-amber-600"
                      fill="none"
                      viewBox="0 0 24 24"
                      strokeWidth="2"
                      stroke="currentColor"
                    >
                      <path
                        strokeLinecap="round"
                        strokeLinejoin="round"
                        d="M9.813 15.904L9 18.75l-.813-2.846a4.5 4.5 0 00-3.09-3.09L2.25 12l2.846-.813a4.5 4.5 0 003.09-3.09L9 5.25l.813 2.846a4.5 4.5 0 003.09 3.09L15.75 12l-2.846.813a4.5 4.5 0 00-3.09 3.09zM18.259 8.715L18 9.75l-.259-1.035a3.375 3.375 0 00-2.455-2.456L14.25 6l1.036-.259a3.375 3.375 0 002.455-2.456L18 2.25l.259 1.035a3.375 3.375 0 002.455 2.456L21.75 6l-1.036.259a3.375 3.375 0 00-2.455 2.456z"
                      />
                    </svg>
                  </div>
                  <div className="flex-1 min-w-0">
                    <span className="font-semibold text-amber-800">Simulation active</span>
                    <span className="text-amber-700 hidden sm:inline">
                      {' '}
                      — Charts reflect planned pre-payments
                    </span>
                  </div>
                </div>
                <button
                  onClick={() => setPlannedPPs([])}
                  className="cursor-pointer shrink-0 rounded-lg border border-amber-300 bg-white px-3 py-1.5 text-xs font-medium text-amber-700 transition-colors hover:bg-amber-50"
                >
                  Clear
                </button>
              </div>
            )}

            {/* Charts */}
            <div className="grid grid-cols-1 gap-4 sm:gap-6 lg:grid-cols-2">
              <BalanceChart summary={summary} simulatedResult={simulatedResult} />
              <CumulativeInterestChart summary={summary} simulatedResult={simulatedResult} />
            </div>

            <div className="grid grid-cols-1 gap-4 sm:gap-6 lg:grid-cols-2">
              <ComparisonChart summary={summary} simulatedResult={simulatedResult} />
              <PaymentBreakupChart summary={summary} />
            </div>

            <PrincipalInterestChart
              schedule={activeResult!.schedule}
              isSimulated={!!simulatedResult}
            />

            <YearlySummaryChart schedule={activeResult!.schedule} isSimulated={!!simulatedResult} />

            {/* Amortization Table */}
            <AmortizationTable
              schedule={activeResult!.schedule}
              isSimulated={!!simulatedResult}
              actualScheduleLength={summary.withPrePayments.schedule.length}
              plannedPPMonths={new Set(plannedPPs.map((pp) => pp.date.substring(0, 7)))}
            />
          </>
        )}
      </main>

      {/* Footer */}
      <footer className="border-t border-slate-200 bg-white mt-16">
        <div className="mx-auto max-w-7xl px-4 sm:px-6 lg:px-8 py-6 text-center text-xs text-slate-400">
          Loan Analyser — All calculations are approximate and for informational purposes only
        </div>
      </footer>

      {isGenerating && summary && loan && activeResult && (
        <PdfReport
          ref={reportRef}
          loan={loan}
          summary={summary}
          prePayments={prePayments}
          rateChanges={rateChanges}
          activeResult={activeResult}
          isSimulated={!!simulatedResult}
        />
      )}
    </div>
  );
};

export default App;

import { forwardRef } from 'react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, Legend } from 'recharts';
import { PieChart, Pie, Cell } from 'recharts';
import { BarChart, Bar } from 'recharts';
import { format } from 'date-fns';
import type {
  LoanInput,
  LoanSummary,
  PrePayment,
  RateChange,
  AmortizationResult,
} from '../../types/loan';
import {
  formatCurrency,
  formatCurrencyShort,
  formatDate,
  formatDateFull,
} from '../../utils/formatters';

interface Props {
  loan: LoanInput;
  summary: LoanSummary;
  prePayments: PrePayment[];
  rateChanges: RateChange[];
  activeResult: AmortizationResult;
  isSimulated: boolean;
}

const CHART_W = 760;
const CHART_H = 280;

export const PdfReport = forwardRef<HTMLDivElement, Props>(function PdfReport(
  { loan, summary, prePayments, rateChanges, activeResult, isSimulated },
  ref,
) {
  const now = new Date();
  const generatedDate = format(now, 'dd MMM yyyy, hh:mm a');
  const { withPrePayments: wp, withoutPrePayments: wop } = summary;

  // --- Balance chart data ---
  const maxLen = Math.max(wp.schedule.length, wop.schedule.length);
  const balanceData = Array.from({ length: maxLen }, (_, i) => ({
    month: i + 1,
    label: formatDate(wop.schedule[i]?.date ?? wp.schedule[i]?.date ?? ''),
    withoutPP: wop.schedule[i]?.closingBalance ?? 0,
    withPP: wp.schedule[i]?.closingBalance ?? 0,
  }));

  // --- Pie chart data ---
  const principalPaid = wp.totalAmountPaid - wp.totalInterest;
  const pieData = [
    { name: 'Principal', value: Math.round(principalPaid) },
    { name: 'Interest', value: Math.round(wp.totalInterest) },
  ];
  const pieTotal = pieData[0].value + pieData[1].value;
  const PIE_COLORS = ['#22c55e', '#ef4444'];

  // --- Yearly summary data ---
  const yearMap = new Map<string, { interest: number; principal: number }>();
  for (const row of activeResult.schedule) {
    const year = row.date.substring(0, 4);
    const existing = yearMap.get(year) || { interest: 0, principal: 0 };
    existing.interest += row.interestComponent;
    existing.principal += row.principalComponent + row.prePayment;
    yearMap.set(year, existing);
  }
  const yearlyData = Array.from(yearMap.entries()).map(([year, vals]) => ({
    year,
    interest: Math.round(vals.interest),
    principal: Math.round(vals.principal),
  }));

  // --- Metrics cards data (same as SummaryCards) ---
  const nowKey = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}`;
  let monthsCompleted = 0;
  for (const row of wp.schedule) {
    if (row.date.substring(0, 7) <= nowKey) monthsCompleted = row.month;
    else break;
  }
  const principalRepaid =
    monthsCompleted > 0
      ? loan.principal - (wp.schedule[monthsCompleted - 1]?.closingBalance ?? 0)
      : 0;
  const progressPct = ((principalRepaid / loan.principal) * 100).toFixed(1);

  const metrics = [
    {
      label: 'Total Interest',
      value: formatCurrency(wp.totalInterest),
      sub: `Original: ${formatCurrency(wop.totalInterest)}`,
    },
    {
      label: 'Total Amount Paid',
      value: formatCurrency(wp.totalAmountPaid),
      sub: `Original: ${formatCurrency(wop.totalAmountPaid)}`,
    },
    {
      label: 'Loan Closure Date',
      value: formatDate(wp.closureDate),
      sub: `Original: ${formatDate(wop.closureDate)}`,
    },
    {
      label: 'Interest Saved',
      value: formatCurrency(summary.interestSaved),
      sub: `${((summary.interestSaved / wop.totalInterest) * 100).toFixed(1)}% reduction`,
    },
    {
      label: 'Months Saved',
      value: `${summary.monthsSaved} months`,
      sub: `${wp.totalMonths} vs ${wop.totalMonths} months`,
    },
    {
      label: 'Interest-to-Principal',
      value: `${((wp.totalInterest / loan.principal) * 100).toFixed(1)}%`,
      sub: `Original: ${((wop.totalInterest / loan.principal) * 100).toFixed(1)}%`,
    },
    {
      label: 'Effective Cost',
      value: `${(wp.totalAmountPaid / loan.principal).toFixed(2)}x`,
      sub: `You pay ${(wp.totalAmountPaid / loan.principal).toFixed(2)}x the borrowed amount`,
    },
    {
      label: 'Loan Progress',
      value: `${progressPct}%`,
      sub: `${monthsCompleted} of ${wp.totalMonths} months completed`,
    },
  ];

  // --- Amortization table: detect rate changes ---
  const schedule = activeResult.schedule;
  const hasRateChanges =
    schedule.length > 1 &&
    schedule.some((row, i) => i > 0 && row.annualRate !== schedule[i - 1].annualRate);

  return (
    <div
      ref={ref}
      style={{
        position: 'fixed',
        left: 0,
        top: 0,
        width: '800px',
        zIndex: -1,
        pointerEvents: 'none',
        background: '#fff',
        color: '#111',
        fontFamily: 'system-ui, -apple-system, sans-serif',
        fontSize: '12px',
        lineHeight: 1.5,
        padding: '24px',
      }}
    >
      {/* === SECTION 1: Header === */}
      {isSimulated && (
        <div
          style={{
            background: '#fef3c7',
            border: '1px solid #f59e0b',
            borderRadius: 6,
            padding: '8px 12px',
            marginBottom: 16,
            fontWeight: 600,
            color: '#92400e',
          }}
        >
          Simulated Scenario — This report reflects planned pre-payments that have not yet been
          made.
        </div>
      )}

      <h1 style={{ fontSize: 22, fontWeight: 700, margin: '0 0 4px' }}>Loan Analysis Report</h1>
      <p style={{ color: '#6b7280', margin: '0 0 16px' }}>Generated on {generatedDate}</p>

      {/* Loan details table */}
      <table style={{ width: '100%', borderCollapse: 'collapse', marginBottom: 16 }}>
        <tbody>
          {(
            [
              ['Principal', formatCurrency(loan.principal)],
              ['Annual Interest Rate', `${loan.annualRate}%`],
              ['EMI', formatCurrency(loan.emi)],
              ['EMI Debit Day', `${loan.emiDebitDay}`],
              ['Start Date', formatDateFull(loan.startDate)],
            ] as const
          ).map(([label, value]) => (
            <tr key={label}>
              <td
                style={{
                  padding: '4px 8px',
                  fontWeight: 600,
                  width: '40%',
                  borderBottom: '1px solid #e5e7eb',
                }}
              >
                {label}
              </td>
              <td style={{ padding: '4px 8px', borderBottom: '1px solid #e5e7eb' }}>{value}</td>
            </tr>
          ))}
        </tbody>
      </table>

      {/* Pre-payments table */}
      {prePayments.length > 0 && (
        <>
          <h3 style={{ fontSize: 14, fontWeight: 600, margin: '12px 0 6px' }}>Pre-Payments</h3>
          <table style={{ width: '100%', borderCollapse: 'collapse', marginBottom: 16 }}>
            <thead>
              <tr style={{ borderBottom: '2px solid #d1d5db' }}>
                <th style={{ padding: '4px 8px', textAlign: 'left', fontWeight: 600 }}>Date</th>
                <th style={{ padding: '4px 8px', textAlign: 'right', fontWeight: 600 }}>Amount</th>
              </tr>
            </thead>
            <tbody>
              {prePayments.map((pp) => (
                <tr key={pp.id} style={{ borderBottom: '1px solid #e5e7eb' }}>
                  <td style={{ padding: '4px 8px' }}>{formatDateFull(pp.date)}</td>
                  <td style={{ padding: '4px 8px', textAlign: 'right' }}>
                    {formatCurrency(pp.amount)}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </>
      )}

      {/* Rate changes table */}
      {rateChanges.length > 0 && (
        <>
          <h3 style={{ fontSize: 14, fontWeight: 600, margin: '12px 0 6px' }}>Rate Changes</h3>
          <table style={{ width: '100%', borderCollapse: 'collapse', marginBottom: 16 }}>
            <thead>
              <tr style={{ borderBottom: '2px solid #d1d5db' }}>
                <th style={{ padding: '4px 8px', textAlign: 'left', fontWeight: 600 }}>
                  Effective Date
                </th>
                <th style={{ padding: '4px 8px', textAlign: 'right', fontWeight: 600 }}>
                  New Rate
                </th>
              </tr>
            </thead>
            <tbody>
              {rateChanges.map((rc) => (
                <tr key={rc.id} style={{ borderBottom: '1px solid #e5e7eb' }}>
                  <td style={{ padding: '4px 8px' }}>{formatDateFull(rc.date)}</td>
                  <td style={{ padding: '4px 8px', textAlign: 'right' }}>{rc.newRate}%</td>
                </tr>
              ))}
            </tbody>
          </table>
        </>
      )}

      {/* === SECTION 2: Summary Metrics === */}
      <h2
        style={{
          fontSize: 16,
          fontWeight: 700,
          margin: '20px 0 10px',
          borderBottom: '2px solid #2563eb',
          paddingBottom: 4,
        }}
      >
        Summary Metrics
      </h2>
      <div
        style={{
          display: 'grid',
          gridTemplateColumns: '1fr 1fr 1fr 1fr',
          gap: 10,
          marginBottom: 20,
        }}
      >
        {metrics.map((m) => (
          <div
            key={m.label}
            style={{ border: '1px solid #d1d5db', borderRadius: 6, padding: '8px 10px' }}
          >
            <div
              style={{
                fontSize: 10,
                fontWeight: 600,
                color: '#6b7280',
                textTransform: 'uppercase',
                letterSpacing: '0.05em',
              }}
            >
              {m.label}
            </div>
            <div style={{ fontSize: 15, fontWeight: 700, marginTop: 2 }}>{m.value}</div>
            <div style={{ fontSize: 10, color: '#9ca3af', marginTop: 2 }}>{m.sub}</div>
          </div>
        ))}
      </div>

      {/* === SECTION 3: Charts === */}
      <h2
        style={{
          fontSize: 16,
          fontWeight: 700,
          margin: '20px 0 10px',
          borderBottom: '2px solid #2563eb',
          paddingBottom: 4,
        }}
      >
        Charts
      </h2>

      {/* Balance Over Time */}
      <div style={{ marginBottom: 20 }}>
        <h3 style={{ fontSize: 13, fontWeight: 600, marginBottom: 6 }}>
          Outstanding Balance Over Time
        </h3>
        <LineChart width={CHART_W} height={CHART_H} data={balanceData}>
          <CartesianGrid strokeDasharray="3 3" />
          <XAxis
            dataKey="month"
            label={{ value: 'Month', position: 'insideBottom', offset: -5 }}
            tick={{ fontSize: 10 }}
          />
          <YAxis tickFormatter={(v) => formatCurrencyShort(v)} width={80} tick={{ fontSize: 10 }} />
          <Tooltip formatter={(value) => formatCurrency(Number(value))} />
          <Legend wrapperStyle={{ fontSize: 10 }} />
          <Line
            type="monotone"
            dataKey="withoutPP"
            name="Original Schedule"
            stroke="#94a3b8"
            strokeWidth={2}
            dot={false}
          />
          <Line
            type="monotone"
            dataKey="withPP"
            name="With Adjustments"
            stroke="#2563eb"
            strokeWidth={2}
            dot={false}
          />
        </LineChart>
      </div>

      {/* Payment Breakup */}
      <div style={{ marginBottom: 20 }} data-html2pdf-page-break="before">
        <h3 style={{ fontSize: 13, fontWeight: 600, marginBottom: 6 }}>Payment Breakup</h3>
        <div style={{ display: 'flex', alignItems: 'center', gap: 20 }}>
          <PieChart width={300} height={CHART_H}>
            <Pie
              data={pieData}
              cx={150}
              cy={130}
              outerRadius={110}
              dataKey="value"
              label={({
                cx,
                cy,
                midAngle,
                innerRadius,
                outerRadius,
                index,
              }: {
                cx?: number;
                cy?: number;
                midAngle?: number;
                innerRadius?: number;
                outerRadius?: number;
                index?: number;
              }) => {
                const RADIAN = Math.PI / 180;
                const radius = (innerRadius ?? 0) + ((outerRadius ?? 0) - (innerRadius ?? 0)) * 0.5;
                const x = (cx ?? 0) + radius * Math.cos(-(midAngle ?? 0) * RADIAN);
                const y = (cy ?? 0) + radius * Math.sin(-(midAngle ?? 0) * RADIAN);
                return (
                  <text
                    x={x}
                    y={y}
                    fill="white"
                    textAnchor="middle"
                    dominantBaseline="central"
                    fontWeight="bold"
                    fontSize={13}
                  >
                    {((pieData[index ?? 0].value / pieTotal) * 100).toFixed(1)}%
                  </text>
                );
              }}
              labelLine={false}
            >
              {pieData.map((_, i) => (
                <Cell key={i} fill={PIE_COLORS[i]} />
              ))}
            </Pie>
            <Tooltip formatter={(value) => formatCurrency(Number(value))} />
          </PieChart>
          <div>
            <div style={{ marginBottom: 6 }}>
              <span
                style={{
                  display: 'inline-block',
                  width: 12,
                  height: 12,
                  borderRadius: '50%',
                  background: '#22c55e',
                  marginRight: 6,
                  verticalAlign: 'middle',
                }}
              />
              Principal: {formatCurrency(principalPaid)}
            </div>
            <div>
              <span
                style={{
                  display: 'inline-block',
                  width: 12,
                  height: 12,
                  borderRadius: '50%',
                  background: '#ef4444',
                  marginRight: 6,
                  verticalAlign: 'middle',
                }}
              />
              Interest: {formatCurrency(wp.totalInterest)}
            </div>
          </div>
        </div>
      </div>

      {/* Yearly Summary */}
      <div style={{ marginBottom: 20 }}>
        <h3 style={{ fontSize: 13, fontWeight: 600, marginBottom: 6 }}>Yearly Summary</h3>
        <BarChart width={CHART_W} height={CHART_H} data={yearlyData}>
          <CartesianGrid strokeDasharray="3 3" />
          <XAxis dataKey="year" tick={{ fontSize: 10 }} />
          <YAxis tickFormatter={(v) => formatCurrencyShort(v)} width={80} tick={{ fontSize: 10 }} />
          <Tooltip
            formatter={(value) => formatCurrency(Number(value))}
            labelFormatter={(l) => `Year ${l}`}
          />
          <Legend wrapperStyle={{ fontSize: 10 }} />
          <Bar dataKey="principal" name="Principal + Prepayment" fill="#22c55e" />
          <Bar dataKey="interest" name="Interest" fill="#ef4444" />
        </BarChart>
      </div>

      {/* === SECTION 4: Amortization Schedule === */}
      <h2
        style={{
          fontSize: 16,
          fontWeight: 700,
          margin: '20px 0 10px',
          borderBottom: '2px solid #2563eb',
          paddingBottom: 4,
        }}
      >
        Amortization Schedule ({schedule.length} months)
      </h2>
      <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 10 }}>
        <thead>
          <tr style={{ borderBottom: '2px solid #374151', background: '#f9fafb' }}>
            <th style={{ padding: '4px 3px', textAlign: 'left', fontWeight: 600 }}>#</th>
            <th style={{ padding: '4px 3px', textAlign: 'left', fontWeight: 600 }}>Date</th>
            {hasRateChanges && (
              <th style={{ padding: '4px 3px', textAlign: 'right', fontWeight: 600 }}>Rate</th>
            )}
            <th style={{ padding: '4px 3px', textAlign: 'right', fontWeight: 600 }}>Opening</th>
            <th style={{ padding: '4px 3px', textAlign: 'right', fontWeight: 600 }}>Interest</th>
            <th style={{ padding: '4px 3px', textAlign: 'right', fontWeight: 600 }}>Principal</th>
            <th style={{ padding: '4px 3px', textAlign: 'right', fontWeight: 600 }}>Pre-Pay</th>
            <th style={{ padding: '4px 3px', textAlign: 'right', fontWeight: 600 }}>Total</th>
            <th style={{ padding: '4px 3px', textAlign: 'right', fontWeight: 600 }}>Closing</th>
          </tr>
        </thead>
        <tbody>
          {schedule.map((row) => {
            const rateChanged =
              hasRateChanges &&
              row.month > 1 &&
              row.annualRate !== schedule[row.month - 2]?.annualRate;
            let bg = '#fff';
            if (row.prePayment > 0)
              bg = '#f0fdf4'; // green-50
            else if (rateChanged) bg = '#eef2ff'; // indigo-50

            return (
              <tr key={row.month} style={{ borderBottom: '1px solid #e5e7eb', background: bg }}>
                <td style={{ padding: '3px' }}>{row.month}</td>
                <td style={{ padding: '3px', whiteSpace: 'nowrap' }}>{formatDate(row.date)}</td>
                {hasRateChanges && (
                  <td
                    style={{
                      padding: '3px',
                      textAlign: 'right',
                      fontWeight: rateChanged ? 700 : 400,
                      color: rateChanged ? '#4338ca' : undefined,
                    }}
                  >
                    {row.annualRate}%
                  </td>
                )}
                <td style={{ padding: '3px', textAlign: 'right' }}>
                  {formatCurrency(row.openingBalance)}
                </td>
                <td style={{ padding: '3px', textAlign: 'right', color: '#dc2626' }}>
                  {formatCurrency(row.interestComponent)}
                </td>
                <td style={{ padding: '3px', textAlign: 'right', color: '#15803d' }}>
                  {formatCurrency(row.principalComponent)}
                </td>
                <td
                  style={{
                    padding: '3px',
                    textAlign: 'right',
                    color: row.prePayment > 0 ? '#2563eb' : '#d1d5db',
                  }}
                >
                  {row.prePayment > 0 ? formatCurrency(row.prePayment) : '-'}
                </td>
                <td style={{ padding: '3px', textAlign: 'right' }}>
                  {formatCurrency(row.totalPayment)}
                </td>
                <td style={{ padding: '3px', textAlign: 'right', fontWeight: 600 }}>
                  {formatCurrency(row.closingBalance)}
                </td>
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  );
});

