            {/* Recommendations */}
            <RecommendationPanel
              data={recommendations}
              loading={recLoading}
              error={recError}
              onFetch={fetchRecommendations}
            />

            {/* What-If Simulator */}
            <WhatIfSimulator
              plannedPPs={plannedPPs}
              onAdd={(pp) => setPlannedPPs((prev) => [...prev, pp])}
              onRemove={(id) => setPlannedPPs((prev) => prev.filter((p) => p.id !== id))}
              currentResult={summary.withPrePayments}
              simulatedResult={simulatedResult}
            />

            {/* Simulation Banner */}
            {simulatedResult && (
              <div className="flex flex-col sm:flex-row items-start sm:items-center gap-3 rounded-xl border border-amber-200 bg-gradient-to-r from-amber-50 to-orange-50 px-4 sm:px-5 py-3 text-sm">
                <div className="flex items-center gap-3 flex-1 min-w-0">
                  <div className="flex h-8 w-8 shrink-0 items-center justify-center rounded-lg bg-amber-100">
                    <svg
                      className="h-4 w-4 text-amber-600"
                      fill="none"
                      viewBox="0 0 24 24"
                      strokeWidth="2"
                      stroke="currentColor"
                    >
                      <path
                        strokeLinecap="round"
                        strokeLinejoin="round"
                        d="M9.813 15.904L9 18.75l-.813-2.846a4.5 4.5 0 00-3.09-3.09L2.25 12l2.846-.813a4.5 4.5 0 003.09-3.09L9 5.25l.813 2.846a4.5 4.5 0 003.09 3.09L15.75 12l-2.846.813a4.5 4.5 0 00-3.09 3.09zM18.259 8.715L18 9.75l-.259-1.035a3.375 3.375 0 00-2.455-2.456L14.25 6l1.036-.259a3.375 3.375 0 002.455-2.456L18 2.25l.259 1.035a3.375 3.375 0 002.455 2.456L21.75 6l-1.036.259a3.375 3.375 0 00-2.455 2.456z"
                      />
                    </svg>
                  </div>
                  <div className="flex-1 min-w-0">
                    <span className="font-semibold text-amber-800">Simulation active</span>
                    <span className="text-amber-700 hidden sm:inline">
                      {' '}
                      — Charts reflect planned pre-payments
                    </span>
                  </div>
                </div>
                <button
                  onClick={() => setPlannedPPs([])}
                  className="cursor-pointer shrink-0 rounded-lg border border-amber-300 bg-white px-3 py-1.5 text-xs font-medium text-amber-700 transition-colors hover:bg-amber-50"
                >
                  Clear
                </button>
              </div>
            )}

            {/* Charts */}
            <div className="grid grid-cols-1 gap-4 sm:gap-6 lg:grid-cols-2">
              <BalanceChart summary={summary} simulatedResult={simulatedResult} />
              <CumulativeInterestChart summary={summary} simulatedResult={simulatedResult} />
            </div>

            <div className="grid grid-cols-1 gap-4 sm:gap-6 lg:grid-cols-2">
              <ComparisonChart summary={summary} simulatedResult={simulatedResult} />
              <PaymentBreakupChart summary={summary} />
            </div>

            <PrincipalInterestChart
              schedule={activeResult!.schedule}
              isSimulated={!!simulatedResult}
            />

            <YearlySummaryChart schedule={activeResult!.schedule} isSimulated={!!simulatedResult} />

            {/* Amortization Table */}
            <AmortizationTable
              schedule={activeResult!.schedule}
              isSimulated={!!simulatedResult}
              actualScheduleLength={summary.withPrePayments.schedule.length}
              plannedPPMonths={new Set(plannedPPs.map((pp) => pp.date.substring(0, 7)))}
            />
          </>
        )}
      </main>

      {/* Footer */}
      <footer className="border-t border-slate-200 bg-white mt-16">
        <div className="mx-auto max-w-7xl px-4 sm:px-6 lg:px-8 py-6 text-center text-xs text-slate-400">
          Loan Analyser — All calculations are approximate and for informational purposes only
        </div>
      </footer>

      {isGenerating && summary && loan && activeResult && (
        <PdfReport
          ref={reportRef}
          loan={loan}
          summary={summary}
          prePayments={prePayments}
          rateChanges={rateChanges}
          activeResult={activeResult}
          isSimulated={!!simulatedResult}
        />
      )}
    </div>
  );
};

export default App;

import { useRef, useState, useCallback, useEffect } from 'react';

export const useExportPdf = () => {
  const reportRef = useRef<HTMLDivElement>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const filenameRef = useRef<string | null>(null);

  // When isGenerating becomes true and PdfReport mounts, wait for
  // Recharts to paint, then capture to PDF.
  useEffect(() => {
    if (!isGenerating) return;

    let cancelled = false;

    (async () => {
      // Give Recharts time to mount & paint SVGs (needs ≥1 frame + layout)
      await new Promise((r) => setTimeout(r, 1000));
      const el = reportRef.current;
      if (cancelled || !el) {
        setIsGenerating(false);
        return;
      }

      try {
        const html2pdf = (await import('html2pdf.js')).default;
        const date = new Date().toISOString().split('T')[0];
        const name = filenameRef.current ?? `loan-report-${date}.pdf`;

        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        await (html2pdf() as any)
          .set({
            margin: 10,
            filename: name,
            image: { type: 'jpeg', quality: 0.98 },
            html2canvas: { scale: 2, useCORS: true, logging: false },
            jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' },
            pagebreak: { mode: ['avoid-all', 'css', 'legacy'] },
          })
          .from(el)
          .save();
      } finally {
        filenameRef.current = null;
        if (!cancelled) setIsGenerating(false);
      }
    })();

    return () => {
      cancelled = true;
    };
  }, [isGenerating]);

  const exportPdf = useCallback(
    (filename?: string) => {
      if (isGenerating) return;
      filenameRef.current = filename ?? null;
      setIsGenerating(true);
    },
    [isGenerating],
  );

  return { reportRef, isGenerating, exportPdf };
};

import { forwardRef } from 'react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, Legend } from 'recharts';
import { PieChart, Pie, Cell } from 'recharts';
import { BarChart, Bar } from 'recharts';
import { format } from 'date-fns';
import type {
  LoanInput,
  LoanSummary,
  PrePayment,
  RateChange,
  AmortizationResult,
} from '../../types/loan';
import {
  formatCurrency,
  formatCurrencyShort,
  formatDate,
  formatDateFull,
} from '../../utils/formatters';

interface Props {
  loan: LoanInput;
  summary: LoanSummary;
  prePayments: PrePayment[];
  rateChanges: RateChange[];
  activeResult: AmortizationResult;
  isSimulated: boolean;
}

const CHART_W = 760;
const CHART_H = 280;

export const PdfReport = forwardRef<HTMLDivElement, Props>(function PdfReport(
  { loan, summary, prePayments, rateChanges, activeResult, isSimulated },
  ref,
) {
  const now = new Date();
  const generatedDate = format(now, 'dd MMM yyyy, hh:mm a');
  const { withPrePayments: wp, withoutPrePayments: wop } = summary;

  // --- Balance chart data ---
  const maxLen = Math.max(wp.schedule.length, wop.schedule.length);
  const balanceData = Array.from({ length: maxLen }, (_, i) => ({
    month: i + 1,
    label: formatDate(wop.schedule[i]?.date ?? wp.schedule[i]?.date ?? ''),
    withoutPP: wop.schedule[i]?.closingBalance ?? 0,
    withPP: wp.schedule[i]?.closingBalance ?? 0,
  }));

  // --- Pie chart data ---
  const principalPaid = wp.totalAmountPaid - wp.totalInterest;
  const pieData = [
    { name: 'Principal', value: Math.round(principalPaid) },
    { name: 'Interest', value: Math.round(wp.totalInterest) },
  ];
