import OpenAI from 'openai';
import type { ChatRequest } from '@/types/chat';

const openai = new OpenAI({
  apiKey: process.env.OPENAI_API_KEY,
});

export const POST = async (request: Request) => {
  try {
    const body: ChatRequest = await request.json();
    const { messages, loanContext } = body;

    if (!messages || messages.length === 0) {
      return new Response(JSON.stringify({ error: 'Messages are required' }), {
        status: 400,
        headers: { 'Content-Type': 'application/json' },
      });
    }

    const ctx = loanContext;
    const systemPrompt = `You are a helpful loan advisor assistant. The user has an active loan with the following details:

- Principal: ₹${ctx.principal.toLocaleString('en-IN')}
- Annual Interest Rate: ${ctx.annualRate}%
- Monthly EMI: ₹${ctx.emi.toLocaleString('en-IN')}
- Loan Start Date: ${ctx.startDate}
- Total Interest (with pre-payments): ₹${ctx.totalInterest.toLocaleString('en-IN')}
