  9→
 10→const fmt = (n: number) =>
 11→  new Intl.NumberFormat('en-IN', {
 12→    style: 'currency',
 13→    currency: 'INR',
 14→    maximumFractionDigits: 0,
 15→  }).format(n);
 16→
 17→const fmtDate = (d: string) => {
 18→  const [y, m, day] = d.split('-');
 19→  const months = [
 20→    'Jan',
 21→    'Feb',
 22→    'Mar',
 23→    'Apr',
 24→    'May',
 25→    'Jun',
 26→    'Jul',
 27→    'Aug',
 28→    'Sep',
 29→    'Oct',
 30→    'Nov',
 31→    'Dec',
 32→  ];
 33→  return `${parseInt(day)} ${months[parseInt(m) - 1]} ${y}`;
 34→};
 35→
 36→const fmtShort = (d: string) => {
 37→  const [y, m] = d.split('-');
 38→  const months = [
 39→    'Jan',
 40→    'Feb',
 41→    'Mar',
 42→    'Apr',
 43→    'May',
 44→    'Jun',
 45→    'Jul',
 46→    'Aug',
 47→    'Sep',
 48→    'Oct',
 49→    'Nov',
 50→    'Dec',
 51→  ];
 52→  return `${months[parseInt(m) - 1]} ${y}`;
 53→};
 54→
 55→interface TemplateData {
 56→  loan: LoanInput;
 57→  summary: LoanSummary;
 58→  prePayments: PrePayment[];
 59→  rateChanges: RateChange[];
 60→  activeResult: AmortizationResult;
 61→  isSimulated: boolean;
 62→}
