 72→  const now = format(new Date(), 'dd MMM yyyy, hh:mm a');
 73→  const { withPrePayments: wp, withoutPrePayments: wop } = summary;
 74→
 75→  // Metrics
 76→  const nowDate = new Date();
 77→  const nowKey = `${nowDate.getFullYear()}-${String(nowDate.getMonth() + 1).padStart(2, '0')}`;
 78→  let monthsCompleted = 0;
 79→  for (const row of wp.schedule) {
 80→    if (row.date.substring(0, 7) <= nowKey) monthsCompleted = row.month;
 81→    else break;
 82→  }
 83→  const principalRepaid =
 84→    monthsCompleted > 0
 85→      ? loan.principal - (wp.schedule[monthsCompleted - 1]?.closingBalance ?? 0)
 86→      : 0;
