128→      sub: `${monthsCompleted} of ${wp.totalMonths} months completed`,
129→    },
130→  ];
131→
132→  // Payment breakup for visual bar
133→  const totalPaid = wp.totalAmountPaid;
134→  const interestPaid = wp.totalInterest;
