136→  const principalPct = ((principalPaidTotal / totalPaid) * 100).toFixed(1);
137→  const interestPct = ((interestPaid / totalPaid) * 100).toFixed(1);
138→
139→  // Yearly summary
140→  const yearMap = new Map<string, { interest: number; principal: number }>();
141→  for (const row of activeResult.schedule) {
