149→    year,
150→    interest: Math.round(vals.interest),
151→    principal: Math.round(vals.principal),
152→  }));
153→  const maxYearlyTotal = Math.max(...yearlyData.map((y) => y.interest + y.principal));
154→
155→  // Amortization schedule
156→  const schedule = activeResult.schedule;
157→  const hasRateChanges =
158→    schedule.length > 1 &&
159→    schedule.some((row, i) => i > 0 && row.annualRate !== schedule[i - 1].annualRate);
160→
161→  // Balance over time — sample every N months for the visual bar chart
