172→  if (scheduleLen > 0 && (scheduleLen - 1) % step !== 0) {
173→    balanceSamples.push({
174→      label: fmtShort(wp.schedule[scheduleLen - 1].date),
175→      balance: wp.schedule[scheduleLen - 1].closingBalance,
176→    });
177→  }
178→  const maxBalance = loan.principal;
179→
180→  // Current rate (last rate in schedule)
181→  const currentRate =
182→    schedule.length > 0 ? schedule[schedule.length - 1].annualRate : loan.annualRate;
183→  const rateChanged = currentRate !== loan.annualRate;
184→
185→  // Total pre-payment amount
186→  const totalPPAmount = prePayments.reduce((sum, pp) => sum + pp.amount, 0);
187→
188→  return `<!DOCTYPE html>
