393→  .row-rate { background: #eef2ff; }
394→  .text-red { color: #dc2626; }
395→  .text-green { color: #15803d; }
396→  .text-blue { color: #2563eb; }
397→  .text-muted { color: #d1d5db; }
398→  .text-indigo { color: #4338ca; }
399→  .fw-bold { font-weight: 700; }
400→  .fw-semi { font-weight: 600; }
401→
402→  .footer {
403→    margin-top: 24px;
404→    padding-top: 10px;
405→    border-top: 1px solid #d1d5db;
406→    font-size: 8px;
407→    color: #9ca3af;
408→    text-align: center;
409→    page-break-inside: avoid;
410→  }
411→
412→  @media print {
413→    .chart-section { page-break-inside: avoid; }
414→  }
415→</style>
416→</head>
417→<body>
418→  <!-- Report Header -->
419→  <div class="report-header">
