421→      <h1>Loan Analysis Report</h1>
422→      <p class="subtitle">Generated on ${now}</p>
423→    </div>
424→    <div style="text-align:right">
425→      <span class="badge ${isSimulated ? 'badge-sim' : 'badge-active'}">${isSimulated ? 'Simulated' : 'Active Loan'}</span>
426→    </div>
427→  </div>
428→
429→  ${isSimulated ? '<div class="sim-banner">Simulated Scenario — This report reflects planned pre-payments that have not yet been made.</div>' : ''}
430→
431→  <!-- Quick Stats -->
432→  <div class="quick-stats">
433→    <div class="quick-stat">
434→      <div class="qs-value">${fmt(loan.principal)}</div>
435→      <div class="qs-label">Principal</div>
436→    </div>
437→    <div class="quick-stat">
438→      <div class="qs-value">${loan.annualRate}%${rateChanged ? ` → ${currentRate}%` : ''}</div>
439→      <div class="qs-label">${rateChanged ? 'Start → Current Rate' : 'Interest Rate'}</div>
440→    </div>
441→    <div class="quick-stat">
442→      <div class="qs-value">${fmt(loan.emi)}</div>
443→      <div class="qs-label">Monthly EMI</div>
444→    </div>
445→    <div class="quick-stat">
446→      <div class="qs-value">${fmtShort(wp.closureDate)}</div>
447→      <div class="qs-label">Closure Date</div>
448→      <div class="qs-sub">${wp.totalMonths} months</div>
449→    </div>
450→  </div>
451→
452→  <!-- Loan Progress -->
453→  <div class="chart-section" style="margin-bottom:14px">
454→    <h3>Loan Progress</h3>
455→    <div class="progress-track">
456→      <div class="progress-fill" style="width:${progressPct}%"></div>
457→    </div>
458→    <div style="display:flex; justify-content:space-between; font-size:9px; color:#64748b">
459→      <span>${progressPct}% repaid (${monthsCompleted} of ${wp.totalMonths} months)</span>
460→      <span>Outstanding: ${fmt(monthsCompleted > 0 ? (wp.schedule[monthsCompleted - 1]?.closingBalance ?? 0) : loan.principal)}</span>
461→    </div>
