463→
464→  <!-- Loan Details -->
465→  <table class="info-table">
466→    <tbody>
467→      <tr><td>Principal</td><td>${fmt(loan.principal)}</td></tr>
468→      <tr><td>Starting Interest Rate</td><td>${loan.annualRate}%</td></tr>
469→      ${rateChanged ? `<tr><td>Current Interest Rate</td><td>${currentRate}%</td></tr>` : ''}
