473→      ${prePayments.length > 0 ? `<tr><td>Total Pre-Payments</td><td>${prePayments.length} pre-payments totalling ${fmt(totalPPAmount)}</td></tr>` : ''}
474→      ${rateChanges.length > 0 ? `<tr><td>Rate Changes</td><td>${rateChanges.length} change(s)</td></tr>` : ''}
475→    </tbody>
476→  </table>
477→
478→  ${
479→    prePayments.length > 0
480→      ? `
481→  <h3>Pre-Payments</h3>
482→  <table class="pp-table">
483→    <thead><tr><th>Date</th><th class="text-right">Amount</th></tr></thead>
484→    <tbody>
485→      ${prePayments.map((pp) => `<tr><td>${fmtDate(pp.date)}</td><td class="text-right">${fmt(pp.amount)}</td></tr>`).join('')}
486→    </tbody>
487→  </table>`
