506→  ${(() => {
507→    // Render metrics in rows of 2 so page breaks fall between rows, not through cards
508→    let html = '';
509→    for (let i = 0; i < metrics.length; i += 2) {
510→      html += '<div class="metrics-grid">';
511→      html += `<div class="metric-card"><div class="metric-label">${metrics[i].label}</div><div class="metric-value">${metrics[i].value}</div><div class="metric-sub">${metrics[i].sub}</div></div>`;
512→      if (metrics[i + 1]) {
513→        html += `<div class="metric-card"><div class="metric-label">${metrics[i + 1].label}</div><div class="metric-value">${metrics[i + 1].value}</div><div class="metric-sub">${metrics[i + 1].sub}</div></div>`;
514→      }
515→      html += '</div>';
516→    }
