526→    <div class="bar-chart">
527→      ${balanceSamples
528→        .map(
529→          (s) => `
530→      <div class="bar-group">
531→        <div class="bar" style="background:#2563eb;height:${((s.balance / maxBalance) * 100).toFixed(1)}%"></div>
532→      </div>`,
533→        )
534→        .join('')}
535→    </div>
536→    <div class="bar-labels">
537→      ${balanceSamples.map((s) => `<span>${s.label}</span>`).join('')}
538→    </div>
539→  </div>
540→
541→  <!-- Payment Breakup -->
542→  <div class="chart-section">
543→    <h3>Payment Breakup</h3>
544→    <div class="breakup-bar">
545→      <div class="breakup-fill" style="background:#22c55e;width:${principalPct}%"></div>
546→      <div class="breakup-fill" style="background:#ef4444;width:${interestPct}%"></div>
547→    </div>
548→    <div class="breakup-legend">
549→      <span><span class="legend-dot" style="background:#22c55e"></span>Principal: ${fmt(principalPaidTotal)} (${principalPct}%)</span>
550→      <span><span class="legend-dot" style="background:#ef4444"></span>Interest: ${fmt(interestPaid)} (${interestPct}%)</span>
551→    </div>
552→  </div>
553→
554→  <!-- Yearly Summary -->
555→  <div class="chart-section">
556→    <h3>Yearly Summary</h3>
557→    <div style="display:flex; gap:12px; font-size:9px; margin-bottom:6px;">
558→      <span><span class="legend-dot" style="background:#22c55e"></span>Principal + Prepayment</span>
559→      <span><span class="legend-dot" style="background:#ef4444"></span>Interest</span>
560→    </div>
561→    <div class="stacked-chart">
562→      ${yearlyData
563→        .map((y) => {
564→          const pPct = ((y.principal / maxYearlyTotal) * 100).toFixed(1);
565→          const iPct = ((y.interest / maxYearlyTotal) * 100).toFixed(1);
566→          return `
567→      <div class="stacked-row">
568→        <span class="stacked-label">${y.year}</span>
569→        <div class="stacked-bar-bg">
570→          <div class="stacked-fill" style="background:#22c55e;width:${pPct}%"></div>
571→          <div class="stacked-fill" style="background:#ef4444;width:${iPct}%"></div>
572→        </div>
573→        <span class="stacked-amounts">${fmt(y.principal + y.interest)}</span>
574→      </div>`;
575→        })
576→        .join('')}
577→    </div>
578→  </div>
579→
580→  <!-- Amortization Schedule -->
581→  <h2>Amortization Schedule (${schedule.length} months)</h2>
582→  <table class="amort-table">
583→    <thead>
584→      <tr>
585→        <th style="text-align:left">#</th>
586→        <th style="text-align:left">Date</th>
587→        ${hasRateChanges ? '<th>Rate</th>' : ''}
588→        <th>Opening</th>
589→        <th>Interest</th>
590→        <th>Principal</th>
591→        <th>Pre-Pay</th>
592→        <th>Total</th>
593→        <th>Closing</th>
594→      </tr>
595→    </thead>
596→    <tbody>
597→      ${schedule
598→        .map((row, idx) => {
599→          const rateChanged =
600→            hasRateChanges &&
601→            row.month > 1 &&
602→            row.annualRate !== schedule[row.month - 2]?.annualRate;
603→          const currentYear = row.date.substring(0, 4);
604→          const prevYear = idx > 0 ? schedule[idx - 1].date.substring(0, 4) : currentYear;
605→          const isYearChange = idx > 0 && currentYear !== prevYear;
606→          const colCount = hasRateChanges ? 9 : 8;
607→
608→          let rowClass = idx % 2 === 0 ? 'row-even' : 'row-odd';
609→          if (row.prePayment > 0) rowClass = 'row-pp';
610→          else if (rateChanged) rowClass = 'row-rate';
611→
612→          const yearSep = isYearChange
613→            ? `<tr class="year-sep"><td colspan="${colCount}">Year ${currentYear}</td></tr>`
614→            : '';
615→
616→          return `${yearSep}<tr class="${rowClass}" style="border-bottom:1px solid #e5e7eb">
617→          <td>${row.month}</td>
618→          <td style="white-space:nowrap">${fmtShort(row.date)}</td>
619→          ${hasRateChanges ? `<td class="${rateChanged ? 'fw-bold text-indigo' : ''}">${row.annualRate}%</td>` : ''}
620→          <td>${fmt(row.openingBalance)}</td>
621→          <td class="text-red">${fmt(row.interestComponent)}</td>
