623→          <td class="${row.prePayment > 0 ? 'text-blue' : 'text-muted'}">${row.prePayment > 0 ? fmt(row.prePayment) : '-'}</td>
624→          <td>${fmt(row.totalPayment)}</td>
625→          <td class="fw-semi">${fmt(row.closingBalance)}</td>
626→        </tr>`;
627→        })
628→        .join('')}
629→    </tbody>
630→  </table>
631→
632→  <div class="footer">
633→    Disclaimer: This report is generated for informational purposes only. All calculations are
634→    approximate and should not be considered as financial advice. Please consult your bank or
