  .bar {
    flex: 1;
    min-width: 4px;
    border-radius: 2px 2px 0 0;
  }
  .bar-labels { display: flex; gap: 2px; font-size: 7px; color: #6b7280; }
  .bar-labels span { flex: 1; text-align: center; overflow: hidden; white-space: nowrap; }

  /* Stacked bar */
