      if (metrics[i + 1]) {
        html += `<div class="metric-card"><div class="metric-label">${metrics[i + 1].label}</div><div class="metric-value">${metrics[i + 1].value}</div><div class="metric-sub">${metrics[i + 1].sub}</div></div>`;
