    width: 190mm;
    max-width: 190mm;
    overflow: hidden;
  }
  h1 { font-size: 20px; font-weight: 700; margin-bottom: 2px; }
  h2 {
    font-size: 14px;
    font-weight: 700;
    margin: 24px 0 10px;
    padding-bottom: 4px;
    border-bottom: 2px solid #2563eb;
    color: #1e293b;
  }
  h3 { font-size: 12px; font-weight: 600; margin-bottom: 6px; color: #334155; }
  .subtitle { color: #6b7280; margin-bottom: 4px; font-size: 11px; }

  .report-header {
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
    margin-bottom: 16px;
    padding-bottom: 14px;
    border-bottom: 1px solid #e5e7eb;
  }
  .report-header .brand {
    font-size: 10px;
    color: #94a3b8;
    margin-top: 4px;
  }
  .report-header .badge {
    display: inline-block;
    padding: 3px 10px;
    border-radius: 20px;
    font-size: 9px;
    font-weight: 600;
  }
  .badge-active { background: #dcfce7; color: #166534; }
  .badge-sim { background: #fef3c7; color: #92400e; }

  .sim-banner {
    background: #fef3c7;
    border: 1px solid #f59e0b;
    border-radius: 6px;
    padding: 6px 12px;
    margin-bottom: 14px;
    font-weight: 600;
    color: #92400e;
    font-size: 11px;
  }

  .info-table { width: 100%; border-collapse: collapse; margin-bottom: 14px; table-layout: fixed; }
  .info-table td {
    padding: 5px 10px;
    border-bottom: 1px solid #e5e7eb;
  }
  .info-table td:first-child { font-weight: 600; width: 40%; color: #374151; }

  /* Quick stats row */
  .quick-stats {
    display: flex;
    gap: 0;
    margin-bottom: 16px;
    border: 1px solid #d1d5db;
    border-radius: 8px;
    overflow: hidden;
  }
  .quick-stat {
    flex: 1;
    padding: 10px 12px;
    text-align: center;
    border-right: 1px solid #e5e7eb;
  }
  .quick-stat:last-child { border-right: none; }
  .quick-stat .qs-value { font-size: 16px; font-weight: 700; color: #1e293b; }
  .quick-stat .qs-label { font-size: 8px; font-weight: 600; color: #6b7280; text-transform: uppercase; letter-spacing: 0.05em; margin-top: 1px; }
  .quick-stat .qs-sub { font-size: 8px; color: #9ca3af; }

  .metrics-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 8px;
    margin-bottom: 8px;
    page-break-inside: avoid;
  }
  .metric-card {
    border: 1px solid #d1d5db;
    border-radius: 6px;
    padding: 8px 10px;
    page-break-inside: avoid;
  }
  .metric-label {
    font-size: 9px;
    font-weight: 600;
    color: #6b7280;
    text-transform: uppercase;
    letter-spacing: 0.05em;
  }
  .metric-value { font-size: 14px; font-weight: 700; margin-top: 1px; }
  .metric-sub { font-size: 9px; color: #9ca3af; margin-top: 1px; }

  .pp-table, .rc-table { width: 100%; border-collapse: collapse; margin-bottom: 14px; }
  .pp-table th, .rc-table th {
    padding: 4px 8px;
    text-align: left;
    font-weight: 600;
    border-bottom: 2px solid #d1d5db;
    font-size: 10px;
  }
  .pp-table td, .rc-table td {
    padding: 4px 8px;
    border-bottom: 1px solid #e5e7eb;
  }
  .text-right { text-align: right; }

  /* Charts section */
  .chart-section { margin-bottom: 20px; page-break-inside: avoid; }

  /* Bar chart with y-axis */
  .bar-chart-wrap { display: flex; gap: 0; }
  .bar-y-axis {
    display: flex;
    flex-direction: column;
    justify-content: space-between;
    align-items: flex-end;
    width: 42px;
    padding-right: 6px;
    font-size: 7px;
    color: #6b7280;
    height: 120px;
  }
  .bar-chart-inner { flex: 1; }
  .bar-chart { display: flex; align-items: flex-end; gap: 2px; height: 120px; margin-bottom: 4px; border-left: 1px solid #cbd5e1; border-bottom: 1px solid #cbd5e1; padding-left: 2px; }
  .bar-group { flex: 1; display: flex; gap: 1px; align-items: flex-end; height: 100%; }
  .bar {
    flex: 1;
    min-width: 4px;
    border-radius: 2px 2px 0 0;
