  }

  /* Progress bar */
  .progress-track {
    height: 8px;
    background: #e2e8f0;
    border-radius: 4px;
    overflow: hidden;
    margin: 6px 0 4px;
  }
  .progress-fill {
    height: 100%;
    background: linear-gradient(90deg, #2563eb, #4f46e5);
    border-radius: 4px;
